"use client";

import Link from "next/link";
import { useState } from "react";

export default function LoginPage() {

const [email,setEmail] = useState("");
const [password,setPassword] = useState("");

const handleLogin = async (e:any) => {
e.preventDefault();

```
const res = await fetch("/api/login",{
  method:"POST",
  headers:{ "Content-Type":"application/json" },
  body: JSON.stringify({ email, password })
});

const data = await res.json();

if(data.message){
  alert("Login successful");
} else {
  alert(data.error);
}
```

};

return (

```
<div className="min-h-screen flex items-center justify-center bg-gray-100">

  <div className="grid md:grid-cols-2 bg-white shadow-xl rounded-2xl overflow-hidden max-w-5xl">

    <div className="hidden md:block">
      <img
        src="https://images.unsplash.com/photo-1582750433449-648ed127bb54"
        alt="Doctor"
        className="h-full w-full object-cover"
      />
    </div>

    <div className="p-10 flex flex-col justify-center">

      <h2 className="text-3xl font-bold mb-2 text-primary">
        Welcome Back
      </h2>

      <p className="text-gray-500 mb-6">
        Login to access MediVerse healthcare services
      </p>

      <form onSubmit={handleLogin} className="space-y-4">

        <input
          type="email"
          placeholder="Email"
          required
          className="w-full border p-3 rounded-lg"
          onChange={(e)=>setEmail(e.target.value)}
        />

        <input
          type="password"
          placeholder="Password"
          required
          className="w-full border p-3 rounded-lg"
          onChange={(e)=>setPassword(e.target.value)}
        />

        <button
          className="w-full bg-primary text-white py-3 rounded-lg hover:opacity-90"
        >
          Login
        </button>

      </form>

      <p className="text-sm mt-6 text-center">
        Don't have an account?{" "}
        <Link href="/signup" className="text-primary font-semibold">
          Signup
        </Link>
      </p>

    </div>

  </div>

</div>
```

);
}
